(function(global){
  'use strict';
  function esc(s){return String(s).replace(/\\/g,'\\\\').replace(/\(/g,'\\(').replace(/\)/g,'\\)').replace(/\r/g,' ').replace(/\n/g,' ');} 
  function PDFDoc(){
    this.pages=[[]]; this.currentPage=0; this.fontSize=11; this.pageWidth=210; this.pageHeight=297;
    this.internal={ pageSize:{ getWidth:()=>this.pageWidth, getHeight:()=>this.pageHeight }, getNumberOfPages:()=>this.pages.length };
  }
  PDFDoc.prototype._page=function(){ return this.pages[this.currentPage]; };
  PDFDoc.prototype._text=function(x,y,t){ this._page().push(`BT /F1 ${this.fontSize} Tf 1 0 0 1 ${Number(x||0).toFixed(2)} ${Number(this.pageHeight-(y||0)).toFixed(2)} Tm (${esc(t)}) Tj ET`); };
  PDFDoc.prototype.setFont=function(){ return this; };
  PDFDoc.prototype.setFontSize=function(v){ this.fontSize=Number(v)||11; return this; };
  PDFDoc.prototype.setTextColor=function(){ return this; };
  PDFDoc.prototype.setFillColor=function(){ return this; };
  PDFDoc.prototype.setDrawColor=function(){ return this; };
  PDFDoc.prototype.setLineWidth=function(){ return this; };
  PDFDoc.prototype.roundedRect=function(){ return this; };
  PDFDoc.prototype.addImage=function(){ return this; };
  PDFDoc.prototype.getTextWidth=function(t){ return String(t||'').length*(this.fontSize*0.35); };
  PDFDoc.prototype.splitTextToSize=function(text,max){
    const words=String(text||'').split(/\s+/); const lines=[]; let line='';
    words.forEach((word)=>{ const probe=line?line+' '+word:word; if((probe.length*this.fontSize*0.35)>max && line){ lines.push(line); line=word; } else { line=probe; }});
    if(line) lines.push(line); return lines.length?lines:[''];
  };
  PDFDoc.prototype.text=function(text,x,y){
    if(Array.isArray(text)){ text.forEach((line,i)=>this._text(x,y+(i*5),line)); return this; }
    this._text(x,y,text); return this;
  };
  PDFDoc.prototype.addPage=function(){ this.pages.push([]); this.currentPage=this.pages.length-1; return this; };
  PDFDoc.prototype.setPage=function(n){ if(n>0 && n<=this.pages.length){ this.currentPage=n-1; } return this; };
  PDFDoc.prototype.putTotalPages=function(){ return this; };
  PDFDoc.prototype.autoTable=function(opts){
    opts=opts||{}; let y=Number(opts.startY||20); const head=opts.head||[]; const body=opts.body||[];
    head.forEach(row=>{ this.text(row.join(' | '),14,y); y+=6;});
    body.forEach(row=>{ this.text(row.join(' | '),14,y); y+=6; if(y>280){ this.addPage(); y=20; }});
    this.lastAutoTable={ finalY:y }; return this;
  };
  PDFDoc.prototype.save=function(filename){
    const objects=[]; const add=obj=>{ objects.push(obj); return objects.length; };
    const pageIds=[];
    const fontId=add('<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>');
    const pagesId=objects.length+2*this.pages.length+1;
    this.pages.forEach((ops)=>{
      const stream=ops.join('\n')||'BT /F1 12 Tf 72 800 Td ( ) Tj ET';
      const contentId=add(`<< /Length ${stream.length} >>\nstream\n${stream}\nendstream`);
      pageIds.push(add(`<< /Type /Page /Parent ${pagesId} 0 R /MediaBox [0 0 595 842] /Contents ${contentId} 0 R /Resources << /Font << /F1 ${fontId} 0 R >> >> >>`));
    });
    add(`<< /Type /Pages /Count ${pageIds.length} /Kids [${pageIds.map(id=>id+' 0 R').join(' ')}] >>`);
    const catalogId=add(`<< /Type /Catalog /Pages ${pagesId} 0 R >>`);
    let pdf='%PDF-1.4\n'; const xref=[0];
    objects.forEach((obj,i)=>{ xref.push(pdf.length); pdf+=`${i+1} 0 obj\n${obj}\nendobj\n`;});
    const xrefPos=pdf.length; pdf+=`xref\n0 ${objects.length+1}\n0000000000 65535 f \n`;
    xref.slice(1).forEach(pos=>{ pdf+=`${String(pos).padStart(10,'0')} 00000 n \n`;});
    pdf+=`trailer << /Size ${objects.length+1} /Root ${catalogId} 0 R >>\nstartxref\n${xrefPos}\n%%EOF`;
    const blob=new Blob([pdf],{type:'application/pdf'}); const a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download=filename||'document.pdf'; a.click(); setTimeout(()=>URL.revokeObjectURL(a.href),1000); return this;
  };
  global.jspdf=global.jspdf||{}; global.jspdf.jsPDF=PDFDoc;
})(window);
